function normalizeUnit(value: string) {
  const trimmed = value.trim();
  const aliases: Record<string, string> = {
    h: "Std",
    std: "Std",
    stunde: "Std",
    stunden: "Std",
    stk: "Stk",
    "stück": "Stk",
    stueck: "Stk",
    pauschale: "Pauschal",
    pauschal: "Pauschal",
    liter: "L",
    ltr: "L",
  };

  return aliases[trimmed.toLowerCase()] ?? trimmed;
}
