function formatMinutes(minutes: number | null) {
  if (!minutes) return "-";

  const hours = Math.floor(minutes / 60);
  const remainingMinutes = minutes % 60;

  if (hours === 0) return `${remainingMinutes} Min.`;
  if (remainingMinutes === 0) return `${hours} Std.`;
  return `${hours} Std. ${remainingMinutes} Min.`;
}

function formatStopwatch(milliseconds: number) {
  const totalSeconds = Math.max(0, Math.floor(milliseconds / 1000));
  const hours = Math.floor(totalSeconds / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  const seconds = totalSeconds % 60;

  if (hours > 0) {
    return `${hours}:${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}h`;
  }

  return `${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}h`;
}

function formatStampDuration(milliseconds: number) {
  const totalSeconds = Math.max(0, Math.floor(milliseconds / 1000));
  const hours = Math.floor(totalSeconds / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  const seconds = totalSeconds % 60;

  return `${hours}:${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}`;
}

function parseGermanDate(value: string) {
  const [day, month, year] = value.split(".").map((part) => Number(part));
  if (!day || !month || !year) return null;
  return new Date(year, month - 1, day);
}

function formatInputDate(date: Date) {
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}-${String(
    date.getDate()
  ).padStart(2, "0")}`;
}

function isDateInRange(date: Date, start: Date, end: Date) {
  const value = new Date(date.getFullYear(), date.getMonth(), date.getDate()).getTime();
  const startValue = new Date(start.getFullYear(), start.getMonth(), start.getDate()).getTime();
  const endValue = new Date(end.getFullYear(), end.getMonth(), end.getDate()).getTime();
  return value >= startValue && value <= endValue;
}

function parseHoursInput(value?: string) {
  if (!value) return 0;
  const normalized = value.replace(",", ".").trim();
  const parsed = Number(normalized);
  return Number.isFinite(parsed) ? Math.max(0, parsed) : 0;
}

function formatHours(value: number) {
  return value.toLocaleString(APP_LOCALE, {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  });
}

function formatHourMinutes(value: number) {
  const sign = value < 0 ? "-" : "";
  const totalMinutes = Math.round(Math.abs(value) * 60);
  const hours = Math.floor(totalMinutes / 60);
  const minutes = totalMinutes % 60;

  return `${sign}${String(hours).padStart(2, "0")}:${String(minutes).padStart(2, "0")}`;
}

function formatMoney(value: number) {
  return `${value.toLocaleString(APP_LOCALE, {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  })} €`;
}

function roundCurrencyValue(value: number) {
  return Math.round((Number(value) || 0) * 100) / 100;
}

function formatCurrencyInputValue(value: number) {
  return roundCurrencyValue(value).toFixed(2);
}

const defaultEmployeeCostCalculation: EmployeeCostCalculation = {
  id: "",
  userId: "",
  monthlySalary: 0,
  fullCostFactor: 1.35,
  annualHours: 2080,
  vacationDays: 30,
  trainingDays: 0,
  sickDays: 10,
  hoursPerDay: 8,
};

function getEmployeeCostMetrics(cost: EmployeeCostCalculation) {
  const deductionDays = cost.vacationDays + cost.trainingDays + cost.sickDays;
  const deductionHours = deductionDays * cost.hoursPerDay;
  const sellableAnnualHours = Math.max(0, cost.annualHours - deductionHours);
  const sellableMonthlyHours = sellableAnnualHours / 12;
  const annualFullCost = cost.monthlySalary * 12 * cost.fullCostFactor;
  const monthlyFullCost = cost.monthlySalary * cost.fullCostFactor;
  const hourlyCost = sellableAnnualHours > 0 ? annualFullCost / sellableAnnualHours : 0;

  return {
    deductionDays,
    deductionHours,
    sellableAnnualHours,
    sellableMonthlyHours,
    annualFullCost,
    monthlyFullCost,
    hourlyCost,
  };
}

