  const sortedNotifications = useMemo(
    () =>
      [...notifications].sort(
        (first, second) =>
          parseAppDateTime(second.createdAt).getTime() - parseAppDateTime(first.createdAt).getTime()
      ),
    [notifications]
  );
  const unreadNotifications = sortedNotifications.filter((notification) => !notification.readAt);
  const visibleNotifications = showNotificationHistory
    ? sortedNotifications.filter((notification) => {
        const normalizedSearchTerm = notificationSearchTerm.trim().toLowerCase();
        if (!normalizedSearchTerm) return true;

        return [notification.subject, notification.body, notification.channel]
          .filter(Boolean)
          .some((value) => value.toLowerCase().includes(normalizedSearchTerm));
      })
    : unreadNotifications;

  async function loadTasks() {
    const res = await fetch("/api/tasks", { cache: "no-store" });

    if (!res.ok) {
      setErrorMessage("Aufgaben konnten nicht geladen werden.");
      return [];
    }

    const data = (await res.json()) as TaskItem[];
    setTasks(data);
    return data;
  }

  async function loadUsers() {
    const res = await fetch("/api/users", { cache: "no-store" });

    if (!res.ok) {
      setErrorMessage("Benutzer konnten nicht geladen werden.");
      setAuthChecked(true);
      return;
    }

    const data = await res.json();
    const storedUserId =
      typeof window !== "undefined" ? window.localStorage.getItem("workpilot-user-id") : null;
    const storedImpersonatedUserId =
      typeof window !== "undefined" ? window.localStorage.getItem("workpilot-impersonated-user-id") : null;
    const storedUser = data.find((demoUser: UserOption) => demoUser.id === storedUserId);
    const storedCanImpersonate =
      storedUser?.role === "ADMIN" || storedUser?.role === "GESCHAEFTSFUEHRER";
    const storedImpersonatedUser =
      storedCanImpersonate && storedImpersonatedUserId
        ? data.find((demoUser: UserOption) => demoUser.id === storedImpersonatedUserId && demoUser.isActive)
        : undefined;
    const effectiveUser = storedImpersonatedUser || storedUser;

    setUsers(data);
    setZustaendigId((current) => current || effectiveUser?.id || data[0]?.id || "");
    setAbsenceUserId((current) => current || effectiveUser?.id || data[0]?.id || "");

    if (storedUser) {
      setAuthenticatedUserId(storedUser.id);
      setImpersonatedUserId(storedImpersonatedUser?.id || "");
      setActiveUserId(effectiveUser?.id || storedUser.id);
      setOwnerFilter((current) => current || effectiveUser?.id || storedUser.id);
      setKanbanOwnerFilter((current) => current || effectiveUser?.id || storedUser.id);
      setPlanningOwnerFilter((current) => current || effectiveUser?.id || storedUser.id);
      setIsAuthenticated(true);
    } else {
      if (storedUserId && typeof window !== "undefined") {
        window.localStorage.removeItem("workpilot-user-id");
        window.localStorage.removeItem("workpilot-impersonated-user-id");
      }
      setIsAuthenticated(false);
      setAuthenticatedUserId("");
      setImpersonatedUserId("");
      setActiveUserId("");
      setOwnerFilter("");
      setKanbanOwnerFilter("");
      setPlanningOwnerFilter("");
    }

    setAuthChecked(true);
  }

  async function loadEmployeeAssessment(userId: string) {
    if (!activeUserId || !userId) return;

    setIsAssessmentLoading(true);
    setAssessmentError("");

    try {
      const res = await fetch(`/api/employee-assessments?actorId=${activeUserId}&userId=${userId}`, {
        cache: "no-store",
      });

      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        setAssessmentError(data.error || "Einschätzung konnte nicht geladen werden.");
        setEmployeeAssessment(emptyEmployeeAssessment);
        return;
      }

      const data = await res.json();
      setEmployeeAssessment(normalizeEmployeeAssessment(data.assessment));
      setAssessmentLoadedUserId(userId);
    } finally {
      setIsAssessmentLoading(false);
    }
  }

  async function saveEmployeeAssessmentSection(
    section:
      | "self"
      | "manager"
      | "measures"
      | "conversation"
      | "unlock-self"
      | "disg-save"
      | "disg-complete"
      | "disg-unlock"
      | "disg-reset",
    data: unknown,
    message = "Einschätzung gespeichert."
  ) {
    if (!activeUserId || !personalAssessmentTargetUserId) return;

    setAssessmentError("");
    setAssessmentSaveMessage("");

    const res = await fetch("/api/employee-assessments", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        actorId: activeUserId,
        userId: personalAssessmentTargetUserId,
        section,
        data,
      }),
    });

    const result = await res.json().catch(() => ({}));
    if (!res.ok) {
      setAssessmentError(result.error || "Einschätzung konnte nicht gespeichert werden.");
      return;
    }

    setEmployeeAssessment(normalizeEmployeeAssessment(result.assessment));
    setAssessmentSaveMessage(message);
  }

