  async function loadIdeaPosts(showNotifications = false) {
    if (!activeUserId) return [];
    const res = await fetch(`/api/idea-store?userId=${activeUserId}`, { cache: "no-store" });
    if (!res.ok) {
      setIdeaStoreError("Ideen-Feed konnte nicht geladen werden.");
      return [];
    }
    const data = (await res.json()) as IdeaStorePost[];
    setIdeaPosts(data);
    if (showNotifications) await loadNotifications(true);
    return data;
  }

  async function createIdeaPost() {
    if (!ideaTitle.trim() || !ideaBody.trim()) {
      setIdeaStoreError("Bitte Titel und Beschreibung der Idee ausfüllen.");
      return;
    }

    const res = await fetch("/api/idea-store", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ title: ideaTitle, body: ideaBody, actorId: activeUserId }),
    });
    const data = await res.json();
    if (!res.ok) {
      setIdeaStoreError(data?.error ?? "Idee konnte nicht gespeichert werden.");
      return;
    }
    setIdeaPosts(data);
    setIdeaTitle("");
    setIdeaBody("");
    setIdeaStoreError("");
    await loadNotifications(true);
  }

  async function updateIdeaPost(ideaId: string, action: "comment" | "like" | "dislike" | "pin") {
    if ((action === "comment" || action === "dislike") && !ideaCommentDrafts[ideaId]?.trim()) {
      setIdeaFeedbackErrors((current) => ({
        ...current,
        [ideaId]:
          action === "dislike"
            ? "Daumen runter kann nur mit Kommentar gespeichert werden."
            : "Bitte einen Kommentar eingeben.",
      }));
      return;
    }

    const res = await fetch("/api/idea-store", {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        ideaId,
        action,
        body: ideaCommentDrafts[ideaId] ?? "",
        actorId: activeUserId,
      }),
    });
    const data = await res.json();
    if (!res.ok) {
      setIdeaFeedbackErrors((current) => ({
        ...current,
        [ideaId]: data?.error ?? "Idee konnte nicht aktualisiert werden.",
      }));
      return;
    }
    setIdeaPosts(data);
    if (action === "comment" || action === "dislike") {
      setIdeaCommentDrafts((current) => ({ ...current, [ideaId]: "" }));
    }
    setIdeaFeedbackErrors((current) => {
      const next = { ...current };
      delete next[ideaId];
      return next;
    });
    setIdeaStoreError("");
    await loadNotifications(true);
  }

  function getIdeaContentBriefing(idea: IdeaStorePost) {
    const commentLines = idea.comments.map(
      (comment) => `- ${comment.authorName || "Unbekannt"} (${formatDeadline(comment.createdAt)}): ${comment.body}`
    );

    return [
      idea.body,
      "",
      `Ursprung: Ideen-Feed · ${idea.title}`,
      commentLines.length > 0 ? "Kommentare aus dem Ideen-Feed:" : "",
      ...commentLines,
    ]
      .filter(Boolean)
      .join("\n");
  }

  function planIdeaAsContent(idea: IdeaStorePost) {
    const plannedDate = formatDateKey(contentCalendarDate);
    const dueDates = getContentDueDates(plannedDate);
    const fallbackOwner = activeUser ?? users.find((user) => user.isActive);

    setEditingContentItemId("");
    setContentDraft({
      ...emptyContentDraft,
      title: idea.title,
      description: getIdeaContentBriefing(idea),
      channel: "Marketing",
      format: "Marketingkonzept",
      ownerUserId: fallbackOwner?.id ?? "",
      plannedDate,
      productionDueDate: dueDates.productionDueDate,
      productionDueTime: dueDates.productionDueTime,
      approvalDueDate: dueDates.approvalDueDate,
      approvalDueTime: dueDates.approvalDueTime,
      plannedTime: dueDates.plannedTime,
      approvalLevel: "gruen",
      status: "In Produktion",
      sourceIdeaId: idea.id,
      sourceIdeaTitle: idea.title,
    });
    setIsContentPostApprovalEditing(false);
    setContentCorrectionNote("");
    setContentError("");
    setIsContentModalOpen(true);
  }

  async function openContentFromIdea(idea: IdeaStorePost) {
    if (!idea.plannedContentItemId) return;

    let entry = contentItems.find((item) => item.id === idea.plannedContentItemId);
    if (!entry) {
      const loadedItems = await loadContentItems();
      entry = loadedItems.find((item) => item.id === idea.plannedContentItemId);
    }

    if (entry) {
      setActiveTab("editorialPlan");
      setOpenSidebarMenus({ contentManagement: true });
      openContentModal(entry);
    }
  }

  function getContentDueDates(plannedDate: string) {
    const baseDate = plannedDate ? new Date(`${plannedDate}T00:00:00`) : new Date();
    const day = baseDate.getDay();
    const thursday = new Date(baseDate);
    thursday.setDate(baseDate.getDate() + (day <= 4 ? 4 - day : 11 - day));
    const friday = new Date(thursday);
    friday.setDate(thursday.getDate() + 1);

    return {
      productionDueDate: formatDateKey(thursday),
      productionDueTime: "17:00",
      approvalDueDate: formatDateKey(friday),
      approvalDueTime: "17:00",
      plannedTime: "09:00",
    };
  }

  function getInitialContentStatus(level: ContentApprovalLevel): ContentStatus {
    return level === "gruen" ? "In Produktion" : "Richtungsfreigabe offen";
  }

  function isContentLockedAfterApproval(contentItem?: ContentItem) {
    return contentItem?.status === "Freigegeben" || contentItem?.status === "Veröffentlicht";
  }

  function openContentModal(contentItem?: ContentItem, mode: "content" | "week" = "content") {
    const plannedDate = contentItem?.plannedDate || formatDateKey(contentCalendarDate);
    const dueDates = getContentDueDates(plannedDate);
    const fallbackOwner = activeUser ?? users.find((user) => user.isActive);

    setEditingContentItemId(contentItem?.id ?? "");
    setContentDraft(
      contentItem
        ? {
            title: contentItem.title,
            description: contentItem.description,
            channel: contentItem.channel,
            format: contentItem.format,
            ownerUserId: contentItem.ownerUserId,
            plannedDate: contentItem.plannedDate,
            productionDueDate: contentItem.productionDueDate,
            productionDueTime: contentItem.productionDueTime || "17:00",
            approvalDueDate: contentItem.approvalDueDate,
            approvalDueTime: contentItem.approvalDueTime || "17:00",
            plannedTime: contentItem.plannedTime || "09:00",
            approvalLevel: contentItem.approvalLevel,
            status: contentItem.status,
            assetLink: contentItem.assetLink,
            imageDataUrl: contentItem.imageDataUrl,
            sourceIdeaId: contentItem.sourceIdeaId,
            sourceIdeaTitle: contentItem.sourceIdeaTitle,
          }
        : {
            ...emptyContentDraft,
            title: mode === "week" ? "Wochenplan" : "",
            channel: mode === "week" ? "Richtlinien" : "Marketing",
            format: mode === "week" ? "Wochenplan" : "Marketingkonzept",
            ownerUserId: fallbackOwner?.id ?? "",
            plannedDate,
            productionDueDate: dueDates.productionDueDate,
            productionDueTime: dueDates.productionDueTime,
            approvalDueDate: dueDates.approvalDueDate,
            approvalDueTime: dueDates.approvalDueTime,
            plannedTime: dueDates.plannedTime,
            approvalLevel: mode === "week" ? "gelb" : "gruen",
            status: mode === "week" ? "Richtungsfreigabe offen" : "In Produktion",
          }
    );
    setIsContentPostApprovalEditing(false);
    setContentCorrectionNote("");
    setContentError("");
    setIsContentModalOpen(true);
  }

  function getContentDraftFromItem(contentItem: ContentItem): ContentDraft {
    return {
      title: contentItem.title,
      description: contentItem.description,
      channel: contentItem.channel,
      format: contentItem.format,
      ownerUserId: contentItem.ownerUserId,
      plannedDate: contentItem.plannedDate,
      productionDueDate: contentItem.productionDueDate,
      productionDueTime: contentItem.productionDueTime || "17:00",
      approvalDueDate: contentItem.approvalDueDate,
      approvalDueTime: contentItem.approvalDueTime || "17:00",
      plannedTime: contentItem.plannedTime || "09:00",
      approvalLevel: contentItem.approvalLevel,
      status: contentItem.status,
      assetLink: contentItem.assetLink,
      imageDataUrl: contentItem.imageDataUrl,
      sourceIdeaId: contentItem.sourceIdeaId,
      sourceIdeaTitle: contentItem.sourceIdeaTitle,
    };
  }

  function updateContentDraft<K extends keyof ContentDraft>(key: K, value: ContentDraft[K]) {
    setContentDraft((current) => {
      const next = { ...current, [key]: value };
      if (key === "approvalLevel") {
        next.status = getInitialContentStatus(value as ContentApprovalLevel);
      }
      return next;
    });
  }

  async function saveContentItem() {
    const owner = users.find((user) => user.id === contentDraft.ownerUserId);
    const method = editingContentItemId ? "PATCH" : "POST";
    const res = await fetch("/api/content-items", {
      method,
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        id: editingContentItemId,
        ...contentDraft,
        status: editingContentItem?.status ?? contentDraft.status,
        postApprovalEdit: isContentPostApprovalEditing,
        ownerName: owner?.name ?? "",
        actorId: activeUserId,
      }),
    });
    const data = await res.json();

    if (!res.ok) {
      setContentError(data?.error ?? "Inhalt konnte nicht gespeichert werden.");
      return;
    }

    setContentItems(data);
    if (contentDraft.sourceIdeaId) {
      await loadIdeaPosts(false);
    }
    setIsContentModalOpen(false);
    setEditingContentItemId("");
    setContentDraft(emptyContentDraft);
    setIsContentPostApprovalEditing(false);
    setContentError("");
    await loadNotifications(true);
  }

  async function updateContentStatus(
    contentItem: ContentItem,
    action:
      | "direction-approve"
      | "mark-produced"
      | "final-approve"
      | "publish"
      | "request-correction"
      | "resubmit"
      | "unlock-post-approval-edit",
    note = ""
  ) {
    const res = await fetch("/api/content-items", {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        id: contentItem.id,
        action,
        note,
        actorId: activeUserId,
      }),
    });
    const data = await res.json();

    if (!res.ok) {
      setContentError(data?.error ?? "Content-Status konnte nicht geändert werden.");
      return;
    }

    setContentItems(data);
    const updatedContentItem = (data as ContentItem[]).find((item) => item.id === contentItem.id);
    if (updatedContentItem && editingContentItemId === contentItem.id) {
      setContentDraft(getContentDraftFromItem(updatedContentItem));
    }
    if (
      action === "mark-produced" ||
      action === "final-approve" ||
      action === "publish" ||
      action === "request-correction" ||
      action === "resubmit"
    ) {
      setIsContentModalOpen(false);
      setEditingContentItemId("");
      setContentDraft(emptyContentDraft);
      setIsContentPostApprovalEditing(false);
    }
    if (action === "unlock-post-approval-edit") {
      setIsContentPostApprovalEditing(true);
    }
    setContentCorrectionNote("");
    setContentError("");
    await loadNotifications(true);
  }

  async function deleteContentItem() {
    if (!editingContentItemId) return;
    if (!window.confirm("Diesen Inhalt wirklich löschen?")) return;

    const res = await fetch("/api/content-items", {
      method: "DELETE",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        id: editingContentItemId,
        actorId: activeUserId,
      }),
    });
    const data = await res.json();

    if (!res.ok) {
      setContentError(data?.error ?? "Inhalt konnte nicht gelöscht werden.");
      return;
    }

    setContentItems(data);
    setIsContentModalOpen(false);
    setEditingContentItemId("");
  }

  async function loadContacts() {
    const res = await fetch("/api/contacts", { cache: "no-store" });

    if (!res.ok) {
      setErrorMessage("Kontakte konnten nicht geladen werden.");
      return;
    }

    const data = (await res.json()) as ContactItem[];
    setContacts(data);
  }

  async function loadCatalogItems() {
    const res = await fetch("/api/catalog-items", { cache: "no-store" });

    if (!res.ok) {
      setErrorMessage("Artikel & Leistungen konnten nicht geladen werden.");
      return;
    }

    const data = (await res.json()) as CatalogItem[];
    setCatalogItems(data);
  }

  async function loadOffers(projectId = "") {
    const query = projectId ? `?projectId=${encodeURIComponent(projectId)}` : "";
    const res = await fetch(`/api/offers${query}`, { cache: "no-store" });

    if (!res.ok) {
      setErrorMessage("Angebote konnten nicht geladen werden.");
      return;
    }

    const data = (await res.json()) as OfferItem[];
    setOffers((currentOffers) => {
      if (!projectId) return data;
      const otherOffers = currentOffers.filter((offer) => offer.projectId !== projectId);
      return [...data, ...otherOffers];
    });
  }

  async function loadInvoices(projectId = "") {
    const query = projectId ? `?projectId=${encodeURIComponent(projectId)}` : "";
    const res = await fetch(`/api/invoices${query}`, { cache: "no-store" });

    if (!res.ok) {
      setErrorMessage("Rechnungen konnten nicht geladen werden.");
      return;
    }

    const data = ((await res.json()) as InvoiceItem[]).filter((invoice) => !isDeletedInvoice(invoice));
    setInvoices((currentInvoices) => {
      if (!projectId) return data;
      const otherInvoices = currentInvoices.filter((invoice) => invoice.projectId !== projectId);
      return [...data, ...otherInvoices];
    });
  }

  async function markInvoiceAsPaid(invoice: InvoiceItem) {
    const res = await fetch("/api/invoices", {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        id: invoice.id,
        action: "mark-paid",
        actorName: activeUser?.name ?? "System",
      }),
    });

    if (!res.ok) {
      const data = await res.json().catch(() => null);
      setErrorMessage(data?.error ?? "Rechnung konnte nicht als bezahlt markiert werden.");
      return;
    }

    await loadInvoices();
    if (selectedProjectFileId) await loadInvoices(selectedProjectFileId);
  }

  async function loadOfferHistory(projectId: string) {
    if (!projectId) return;
    const res = await fetch(`/api/offers?historyProjectId=${encodeURIComponent(projectId)}`, {
      cache: "no-store",
    });

    if (!res.ok) {
      setErrorMessage("Angebotshistorie konnte nicht geladen werden.");
      return;
    }

    const data = (await res.json()) as OfferHistoryItem[];
    setOfferHistory((currentHistory) => {
      const otherHistory = currentHistory.filter((entry) => entry.projectId !== projectId);
      return [...data, ...otherHistory];
    });
  }

  function getCatalogPackageSalesPrice(item: CatalogItem) {
    if (item.type !== "package") return item.salesPrice;
    if (item.salesPrice > 0) return item.salesPrice;
    return item.packageItems.reduce(
      (sum, packageItem) =>
        sum + (packageItem.priceOverride ?? packageItem.componentSalesPrice) * packageItem.quantity,
      0
    );
  }

  function getCatalogPackagePurchasePrice(item: CatalogItem) {
    if (item.type !== "package") return item.purchasePrice;
    return item.packageItems.reduce(
      (sum, packageItem) => sum + packageItem.componentPurchasePrice * packageItem.quantity,
      0
    );
  }

  function getCatalogMaterialPurchasePrice(item: CatalogItem) {
    if (item.type === "service") return 0;
    if (item.type !== "package") return item.purchasePrice;
    return item.packageItems
      .filter((packageItem) => packageItem.componentType === "article")
      .reduce((sum, packageItem) => sum + packageItem.componentPurchasePrice * packageItem.quantity, 0);
  }

  function getCatalogLaborPurchasePrice(item: CatalogItem) {
    if (item.type === "service") return item.purchasePrice;
    if (item.type !== "package") return 0;
    return item.packageItems
      .filter((packageItem) => packageItem.componentType === "service")
      .reduce((sum, packageItem) => sum + packageItem.componentPurchasePrice * packageItem.quantity, 0);
  }

  function getDefaultLaborCostRateKeyForCatalogItem(item: Pick<CatalogItem, "type" | "defaultPlanningBoard" | "defaultPlanningGroup">) {
    if (item.type !== "service") return "";
    if (item.defaultPlanningBoard === "OK immocare") {
      return item.defaultPlanningGroup === "TZK" ? "ok-immocare-tzk" : "ok-immocare-vzk";
    }
    return "ok-solutions";
  }

  function createOfferLineFromCatalogItem(item: CatalogItem): OfferLineDraft {
    return {
      id: crypto.randomUUID(),
      catalogItemId: item.id,
      catalogType: item.type,
      quantity: 1,
      unit: item.unit || "Stk",
      title: item.name,
      description: item.description || item.category || "",
      unitPrice: getCatalogPackageSalesPrice(item),
      discountPercent: 0,
      laborCostRateKey: item.laborCostRateKey || getDefaultLaborCostRateKeyForCatalogItem(item),
      laborCostRate: roundCurrencyValue(getCatalogLaborPurchasePrice(item)),
      vatRate: item.vatRate || 19,
      laborItems: [],
    };
  }

  function createEmptyOfferLine(vatRate = 19): OfferLineDraft {
    return {
      id: crypto.randomUUID(),
      catalogItemId: "",
      catalogType: "",
      quantity: 1,
      unit: "Stk",
      title: "",
      description: "",
      unitPrice: 0,
      discountPercent: 0,
      laborCostRateKey: "",
      laborCostRate: 0,
      vatRate,
      laborItems: [],
    };
  }

  function getOfferLineTypeLabel(type: CatalogItemType | "") {
    if (type === "service") return "Leistung";
    if (type === "package") return "Paket";
    if (type === "article") return "Material";
    return "Freie Position";
  }

  function canPlanOfferLineLabor(line: OfferLineDraft) {
    return line.catalogType === "service" || line.catalogType === "package";
  }

  function getDefaultBranchAllocations(board: PlanningBoardCompany = "OK solutions"): BranchAllocations {
    return board === "OK immocare"
      ? { okSolutions: 0, okImmocare: 100, okImmocareVzk: 100, okImmocareTzk: 0 }
      : { okSolutions: 100, okImmocare: 0, okImmocareVzk: 0, okImmocareTzk: 0 };
  }

  function normalizeBranchAllocations(
    value?: Partial<BranchAllocations> | null,
    fallbackBoard: PlanningBoardCompany = "OK solutions"
  ): BranchAllocations {
    const fallback = getDefaultBranchAllocations(fallbackBoard);
    const legacyImmocare = Number(value?.okImmocare ?? fallback.okImmocare) || 0;
    const rawVzk =
      value?.okImmocareVzk !== undefined
        ? Number(value.okImmocareVzk) || 0
        : fallbackBoard === "OK immocare"
          ? legacyImmocare
          : 0;
    const rawTzk = value?.okImmocareTzk !== undefined ? Number(value.okImmocareTzk) || 0 : 0;
    const okImmocareVzk = clampPercent(rawVzk);
    const okImmocareTzk = clampPercent(rawTzk);
    const okImmocare = clampPercent(okImmocareVzk + okImmocareTzk);
    return {
      okSolutions: clampPercent(Number(value?.okSolutions ?? fallback.okSolutions) || 0),
      okImmocare,
      okImmocareVzk,
      okImmocareTzk,
    };
  }

  function getBranchAllocationTotal(allocations: BranchAllocations) {
    return (
      Number(allocations.okSolutions || 0) +
      Number(allocations.okImmocareVzk || 0) +
      Number(allocations.okImmocareTzk || 0)
    );
  }

  function createBoundedBranchAllocations(
    current: BranchAllocations,
    key: "okSolutions" | "okImmocareVzk" | "okImmocareTzk",
    rawValue: number
  ): BranchAllocations {
    const value = clampPercent(rawValue);
    const next = normalizeBranchAllocations(current);
    const otherKeys = (["okSolutions", "okImmocareVzk", "okImmocareTzk"] as const).filter((item) => item !== key);

    next[key] = value;
    let overflow = getBranchAllocationTotal(next) - 100;
    if (overflow > 0) {
      [...otherKeys].reverse().forEach((item) => {
        if (overflow <= 0) return;
        const currentValue = Number(next[item] || 0);
        const reduction = Math.min(currentValue, overflow);
        next[item] = clampPercent(currentValue - reduction);
        overflow -= reduction;
      });
    }

    next.okImmocare = clampPercent(Number(next.okImmocareVzk || 0) + Number(next.okImmocareTzk || 0));
    return next;
  }

  function getUserPlanningBoard(user: UserOption) {
    return user.planningBoard === "OK immocare" ? "OK immocare" : "OK solutions";
  }

  function getUserBranchAllocations(user: UserOption) {
    return normalizeBranchAllocations(user.branchAllocations, getUserPlanningBoard(user));
  }

  function getBranchAllocationShare(user: UserOption, board: PlanningBoardCompany) {
    const allocations = getUserBranchAllocations(user);
    return (board === "OK immocare" ? allocations.okImmocare : allocations.okSolutions) / 100;
  }

  function getLaborCostAllocationShare(user: UserOption, board: PlanningBoardCompany, planningGroup = "") {
    const allocations = getUserBranchAllocations(user);
    if (board === "OK solutions") return allocations.okSolutions / 100;
    if (planningGroup === "TZK") return (allocations.okImmocareTzk ?? 0) / 100;
    if (planningGroup === "VZK") return (allocations.okImmocareVzk ?? allocations.okImmocare) / 100;
    return allocations.okImmocare / 100;
  }

  function getPrimaryBranchFromAllocations(allocations: BranchAllocations): PlanningBoardCompany {
    return allocations.okImmocare > allocations.okSolutions ? "OK immocare" : "OK solutions";
  }

  function formatBranchAllocations(user: UserOption) {
    const allocations = getUserBranchAllocations(user);
    const parts = [
      allocations.okSolutions > 0 ? `OK solutions ${formatHours(allocations.okSolutions)}%` : "",
      (allocations.okImmocareVzk ?? 0) > 0 ? `OK immocare VZK ${formatHours(allocations.okImmocareVzk ?? 0)}%` : "",
      (allocations.okImmocareTzk ?? 0) > 0 ? `OK immocare TZK ${formatHours(allocations.okImmocareTzk ?? 0)}%` : "",
    ].filter(Boolean);
    return parts.join(" / ") || "-";
  }

  function getEmployeeHourlyCostRate(userId: string) {
    const cost = employeeCostCalculations[userId];
    return cost ? getEmployeeCostMetrics(cost).hourlyCost : 0;
  }

  function getAverageLaborCostRate(board: PlanningBoardCompany, planningGroup = "") {
    const boardUsers = users.filter(
      (user) =>
        user.isActive &&
        user.includeInLaborCostRate !== false &&
        getLaborCostAllocationShare(user, board, planningGroup) > 0
    );
    const allocationTotal = boardUsers.reduce((sum, user) => sum + getLaborCostAllocationShare(user, board, planningGroup), 0);
    const total = boardUsers.reduce(
      (sum, user) => sum + getEmployeeHourlyCostRate(user.id) * getLaborCostAllocationShare(user, board, planningGroup),
      0
    );
    return {
      board,
      planningGroup,
      label: planningGroup ? `${board} ${planningGroup}` : board,
      users: boardUsers,
      total,
      allocationTotal,
      average: boardUsers.length > 0 ? total / boardUsers.length : 0,
      count: boardUsers.length,
    };
  }

  function getLaborCostRateOptions() {
    return [
      { key: "ok-solutions", label: "OK solutions", rate: getAverageLaborCostRate("OK solutions").average },
      { key: "ok-immocare-vzk", label: "OK immocare VZK", rate: getAverageLaborCostRate("OK immocare", "VZK").average },
      { key: "ok-immocare-tzk", label: "OK immocare TZK", rate: getAverageLaborCostRate("OK immocare", "TZK").average },
    ];
  }

  function getLaborCostRateOption(key: string) {
    return getLaborCostRateOptions().find((option) => option.key === key) ?? null;
  }

  function getProjectLaborCostBoard(project?: HeroProjectPreview | null): PlanningBoardCompany {
    return project?.projectType === "Projekt OK immocare" || project?.branch === "OK immocare GmbH"
      ? "OK immocare"
      : "OK solutions";
  }

  function getOfferDraftLaborCostRate() {
    const selectedProject =
      selectedProjectFile || heroProjects.find((project) => project.id === upsellOfferProjectId) || null;
    const board = getProjectLaborCostBoard(selectedProject);
    return getAverageLaborCostRate(board);
  }

  function createOfferLaborItem(user?: UserOption): OfferLineLaborDraft {
    const targetUser = user ?? users.find((item) => item.isActive);
    const hourlyCostRate = targetUser ? getEmployeeHourlyCostRate(targetUser.id) : 0;
    return {
      id: crypto.randomUUID(),
      userId: targetUser?.id ?? "",
      employeeName: targetUser?.name ?? "",
      plannedHours: 0,
      hourlyCostRate,
      totalCost: 0,
    };
  }

  function getOfferLineLaborHours(line: OfferLineDraft) {
    return line.laborItems.reduce((sum, labor) => sum + Number(labor.plannedHours || 0), 0);
  }

  function clampOfferLaborItems(
    laborItems: OfferLineLaborDraft[],
    maxHours: number
  ): OfferLineLaborDraft[] {
    let remainingHours = Math.max(Number(maxHours || 0), 0);
    return laborItems.map((labor) => {
      const plannedHours = Math.min(Math.max(Number(labor.plannedHours || 0), 0), remainingHours);
      remainingHours -= plannedHours;
      return {
        ...labor,
        plannedHours,
        totalCost: plannedHours * Number(labor.hourlyCostRate || 0),
      };
    });
  }

  function updateOfferLine(index: number, patch: Partial<OfferLineDraft>) {
    setOfferDraft((current) => ({
      ...current,
      lines: current.lines.map((line, lineIndex) => {
        if (lineIndex !== index) return line;
        const selectedItem = patch.catalogItemId
          ? catalogItems.find((item) => item.id === patch.catalogItemId)
          : null;
        if (selectedItem) {
          const nextQuantity = patch.quantity ?? line.quantity;
          const nextLine = createOfferLineFromCatalogItem(selectedItem);
          return {
            ...line,
            ...nextLine,
            id: line.id,
            quantity: nextQuantity,
            laborItems:
              nextLine.catalogType === "service" || nextLine.catalogType === "package"
                ? clampOfferLaborItems(line.laborItems, nextQuantity)
                : [],
          };
        }
      const nextLine = { ...line, ...patch };
        if (Object.prototype.hasOwnProperty.call(patch, "unit")) {
          nextLine.unit = normalizeUnit(String(patch.unit ?? ""));
        }
        if (Object.prototype.hasOwnProperty.call(patch, "quantity")) {
          return {
            ...nextLine,
            laborItems: canPlanOfferLineLabor(nextLine)
              ? clampOfferLaborItems(nextLine.laborItems, nextLine.quantity)
              : [],
          };
        }
        return nextLine;
      }),
    }));
  }

  function updateOfferLineLabor(
    lineIndex: number,
    laborId: string,
    patch: Partial<OfferLineLaborDraft>
  ) {
    setOfferDraft((current) => ({
      ...current,
      lines: current.lines.map((line, currentLineIndex) => {
        if (currentLineIndex !== lineIndex) return line;
        const maxHours = Math.max(Number(line.quantity || 0), 0);

        return {
          ...line,
          laborItems: line.laborItems.map((labor) => {
            if (labor.id !== laborId) return labor;
            const selectedUser = patch.userId
              ? users.find((user) => user.id === patch.userId)
              : null;
            const otherHours = line.laborItems
              .filter((item) => item.id !== laborId)
              .reduce((sum, item) => sum + Number(item.plannedHours || 0), 0);
            const availableHours = Math.max(maxHours - otherHours, 0);
            const plannedHours = Math.min(
              Math.max(Number(patch.plannedHours ?? labor.plannedHours), 0),
              availableHours
            );
            const hourlyCostRate = patch.userId
              ? getEmployeeHourlyCostRate(patch.userId)
              : patch.hourlyCostRate ?? labor.hourlyCostRate;

            return {
              ...labor,
              ...patch,
              employeeName: selectedUser?.name ?? patch.employeeName ?? labor.employeeName,
              plannedHours,
              hourlyCostRate,
              totalCost: plannedHours * hourlyCostRate,
            };
          }),
        };
      }),
    }));
  }

  function addOfferLineLabor(lineIndex: number) {
    setOfferDraft((current) => ({
      ...current,
      lines: current.lines.map((line, currentLineIndex) =>
        currentLineIndex === lineIndex && getOfferLineLaborHours(line) < Number(line.quantity || 0)
          ? { ...line, laborItems: [...line.laborItems, createOfferLaborItem()] }
          : line
      ),
    }));
  }

  function removeOfferLineLabor(lineIndex: number, laborId: string) {
    setOfferDraft((current) => ({
      ...current,
      lines: current.lines.map((line, currentLineIndex) =>
        currentLineIndex === lineIndex
          ? { ...line, laborItems: line.laborItems.filter((labor) => labor.id !== laborId) }
          : line
      ),
    }));
  }

  function selectOfferCatalogItem(index: number, itemId: string) {
    updateOfferLine(index, { catalogItemId: itemId });
    const lineId = offerDraft.lines[index]?.id;
    if (lineId) {
      setOfferLineSearchTerms((current) => ({ ...current, [lineId]: "" }));
    }
    setOpenOfferLinePickerId("");
  }

  function removeOfferLine(index: number) {
    setOfferDraft((current) => ({
      ...current,
      lines: current.lines.filter((_, lineIndex) => lineIndex !== index),
    }));
    const lineId = offerDraft.lines[index]?.id;
    if (lineId) {
      setOfferLineSearchTerms((current) => {
        const next = { ...current };
        delete next[lineId];
        return next;
      });
    }
  }

  function addOfferLine() {
    setOfferDraft((current) => ({
      ...current,
      lines: [...current.lines, createEmptyOfferLine(current.vatRate)],
    }));
  }

  function closeOfferModal() {
    setIsOfferModalOpen(false);
    setEditingOfferId("");
    setUpsellOfferProjectId("");
    setIsOfferExecutionMonthPickerOpen(false);
    setIsOfferExecutionEndMonthPickerOpen(false);
  }

  function openOfferModal(project: HeroProjectPreview, options: { fromUpsell?: boolean; asAddendum?: boolean } = {}) {
    const isImmocare =
      (project.projectType ?? "").toLowerCase().includes("immocare") ||
      (project.projectNumber ?? "").toLowerCase().startsWith("oki");
    const addressParts = (project.address || "").split(",").map((part) => part.trim()).filter(Boolean);
    const isRecurringProject = getProjectKind(project).startsWith("Dauer");
    const recurringStartMonth = options.asAddendum
      ? `${reportNow.getFullYear()}-${String(reportNow.getMonth() + 1).padStart(2, "0")}`
      : project.projectRuntimeFrom
        ? project.projectRuntimeFrom.slice(0, 7)
        : "";
    const recurringEndMonth = project.projectRuntimeUntil ? project.projectRuntimeUntil.slice(0, 7) : "";
    setOfferDraft({
      ...emptyOfferDraft,
      offerType: options.asAddendum ? "addendum" : "base",
      plannedExecutionMonth: isRecurringProject ? recurringStartMonth : "",
      plannedExecutionEndMonth: isRecurringProject ? recurringEndMonth : "",
      company: isImmocare ? "OK immocare" : "OK solutions",
      customerName: project.customer || "",
      customerStreet: addressParts[0] || project.address || "",
      customerCity: addressParts.slice(1).join(", "),
      internalContactName: activeUser?.name || "Christian Eid",
      internalEmail: activeUser?.email || "",
      lines: [createEmptyOfferLine(emptyOfferDraft.vatRate)],
    });
    setOfferError("");
    setEditingOfferId("");
    setOfferPreviewDataUrl("");
    setOfferLineSearchTerms({});
    setOpenOfferLinePickerId("");
    setIsOfferExecutionMonthPickerOpen(false);
    setIsOfferExecutionEndMonthPickerOpen(false);
    setOfferExecutionMonthPickerYear(
      recurringStartMonth ? Number(recurringStartMonth.slice(0, 4)) : reportNow.getFullYear()
    );
    setOfferExecutionEndMonthPickerYear(
      recurringEndMonth ? Number(recurringEndMonth.slice(0, 4)) : reportNow.getFullYear()
    );
    setUpsellOfferProjectId(options.fromUpsell ? project.id : "");
    setIsOfferModalOpen(true);
  }

  function openEditOfferModal(offer: OfferItem) {
    const offerExecutionYear = Number((offer.plannedExecutionMonth || "").slice(0, 4));
    const isRecurringProject = selectedProjectFile ? getProjectKind(selectedProjectFile).startsWith("Dauer") : false;
    setOfferDraft({
      company: offer.company,
      offerType: offer.offerType === "addendum" ? "addendum" : "base",
      addendumMode:
        offer.addendumMode === "replacement" || offer.addendumMode === "reduction"
          ? offer.addendumMode
          : "addition",
      plannedExecutionEndMonth:
        offer.plannedExecutionEndMonth ||
        (isRecurringProject && selectedProjectFile?.projectRuntimeUntil
          ? selectedProjectFile.projectRuntimeUntil.slice(0, 7)
          : ""),
      parentOfferId: offer.parentOfferId || "",
      customerName: offer.customerName,
      customerStreet: offer.customerStreet,
      customerCity: offer.customerCity,
      contactName: offer.contactName,
      internalContactName: offer.internalContactName,
      internalPhone: offer.internalPhone,
      internalEmail: offer.internalEmail,
      plannedExecutionMonth: offer.plannedExecutionMonth || "",
      introText: offer.introText || emptyOfferDraft.introText,
      closingText: offer.closingText || emptyOfferDraft.closingText,
      vatRate: offer.vatRate || 19,
      discountPercent: offer.discountPercent ?? 0,
      lines:
        offer.lines.length > 0
          ? offer.lines.map((line) => ({
              id: line.id || crypto.randomUUID(),
              catalogItemId: line.catalogItemId,
              catalogType: line.catalogType,
              quantity: line.quantity,
              unit: line.unit,
              title: line.title,
              description: line.description,
              unitPrice: line.unitPrice,
              discountPercent: line.discountPercent ?? 0,
              laborCostRateKey: line.laborCostRateKey || "",
              laborCostRate: roundCurrencyValue(line.laborCostRate || 0),
              vatRate: line.vatRate,
              laborItems: (line.laborItems ?? []).map((labor) => ({
                id: labor.id || crypto.randomUUID(),
                userId: labor.userId,
                employeeName: labor.employeeName,
                plannedHours: labor.plannedHours,
                hourlyCostRate: labor.hourlyCostRate,
                totalCost: labor.totalCost,
              })),
            }))
          : [createEmptyOfferLine(offer.vatRate || 19)],
    });
    setEditingOfferId(offer.id);
    setOfferError("");
    setOfferPreviewDataUrl(offer.pdfAvailable ? `/api/offers?pdfId=${encodeURIComponent(offer.id)}` : "");
    setOfferLineSearchTerms({});
    setOpenOfferLinePickerId("");
    setIsOfferExecutionMonthPickerOpen(false);
    setIsOfferExecutionEndMonthPickerOpen(false);
    setOfferExecutionMonthPickerYear(Number.isFinite(offerExecutionYear) ? offerExecutionYear : reportNow.getFullYear());
    setOfferExecutionEndMonthPickerYear(
      Number.isFinite(Number((offer.plannedExecutionEndMonth || selectedProjectFile?.projectRuntimeUntil || "").slice(0, 4)))
        ? Number((offer.plannedExecutionEndMonth || selectedProjectFile?.projectRuntimeUntil || "").slice(0, 4))
        : reportNow.getFullYear()
    );
    setUpsellOfferProjectId("");
    setIsOfferModalOpen(true);
  }

  async function generateOfferPreview() {
    if (!selectedProjectFile) return;
    setIsGeneratingOfferPreview(true);
    setOfferError("");

    const editingOffer = offers.find((offer) => offer.id === editingOfferId);
    const offerPayload = {
      ...offerDraft,
      lines: offerDraft.lines.map((line) => ({
        ...line,
        laborCostRate: roundCurrencyValue(line.laborCostRate || 0),
        laborItems: [],
      })),
    };
    const res = await fetch("/api/offers", {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        ...offerPayload,
        offerNumber: editingOffer?.offerNumber || "VORSCHAU",
        projectId: selectedProjectFile.id,
        projectNumber: selectedProjectFile.projectNumber || selectedProjectFile.id,
        projectTitle: selectedProjectFile.title,
      }),
    });

    setIsGeneratingOfferPreview(false);

    if (!res.ok) {
      const data = await res.json().catch(() => null);
      setOfferError(data?.error ?? "Vorschau konnte nicht erstellt werden.");
      return;
    }

    const data = (await res.json()) as { pdfDataUrl: string };
    setOfferPreviewDataUrl(data.pdfDataUrl);
  }

  async function saveOffer(options: { asDraft?: boolean } = {}) {
    if (!selectedProjectFile) return;
    const saveAsDraft = Boolean(options.asDraft);
    const validationMessage = saveAsDraft ? "" : getOfferSaveValidationMessage();
    if (validationMessage) {
      setOfferError(validationMessage);
      return;
    }
    setIsSavingOffer(true);
    setOfferError("");
    const offerPayload = {
      ...offerDraft,
      lines: offerDraft.lines.map((line) => ({
        ...line,
        laborCostRate: roundCurrencyValue(line.laborCostRate || 0),
        laborItems: [],
      })),
    };

    const res = await fetch("/api/offers", {
      method: editingOfferId ? "PATCH" : "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        id: editingOfferId,
        ...offerPayload,
        saveAsDraft,
        projectId: selectedProjectFile.id,
        projectNumber: selectedProjectFile.projectNumber || selectedProjectFile.id,
        projectTitle: selectedProjectFile.title,
      }),
    });

    setIsSavingOffer(false);

    if (!res.ok) {
      const data = await res.json().catch(() => null);
      setOfferError(data?.error ?? "Angebot konnte nicht erstellt werden.");
      return;
    }

    const savedOffer = (await res.json()) as OfferItem;
    setOffers((currentOffers) => [savedOffer, ...currentOffers.filter((offer) => offer.id !== savedOffer.id)]);
    await loadOfferHistory(selectedProjectFile.id);
    await addProjectLogbookEntry(
      selectedProjectFile.id,
      "Angebot",
      `${saveAsDraft ? "Angebotsentwurf gespeichert" : editingOfferId ? "Angebot geändert" : "Angebot erstellt"}: ${savedOffer.offerNumber} (${formatMoney(
        savedOffer.grossTotal
      )} brutto).`
    );
    if (!saveAsDraft && !editingOfferId && upsellOfferProjectId === selectedProjectFile.id) {
      const potential = projectPotentials.find(
        (item) => item.projectId === selectedProjectFile.id && ["open", "follow_up"].includes(item.status)
      );
      if (potential) {
        await updateProjectPotential(potential, "offered", {
          note: `Angebot ${savedOffer.offerNumber} erstellt.`,
        });
      }
      await addProjectLogbookEntry(
        selectedProjectFile.id,
        "Zusatzverkauf: Angebot erstellt",
        `Aus dem erkannten Zusatzverkauf wurde Angebot ${savedOffer.offerNumber} erstellt.`
      );
      setUpsellOfferProjectId("");
    }
    setSelectedProjectDocumentType(savedOffer.offerType === "addendum" ? "Angebote: Nachtragsangebote" : "Angebote");
    setProjectFileTab("documents");
    setIsOfferModalOpen(false);
    setEditingOfferId("");
    if (!saveAsDraft && savedOffer.pdfAvailable) {
      window.open(`/api/offers?pdfId=${encodeURIComponent(savedOffer.id)}`, "_blank");
    }
  }

  function getOfferSaveValidationMessage() {
    if (!offerDraft.plannedExecutionMonth) {
      return "Bitte geplanten Ausführungsmonat auswählen.";
    }
    const isRecurringOfferProject = selectedProjectFile ? getProjectKind(selectedProjectFile).startsWith("Dauer") : false;
    if (isRecurringOfferProject && !offerDraft.plannedExecutionEndMonth) {
      return "Bitte beim Dauerlaeufer den Ausfuehrungszeitraum bis auswaehlen.";
    }
    if (
      offerDraft.plannedExecutionEndMonth &&
      offerDraft.plannedExecutionEndMonth < offerDraft.plannedExecutionMonth
    ) {
      return "Bitte beim Ausfuehrungszeitraum ein Enddatum nach dem Startmonat waehlen.";
    }
    if (offerDraft.lines.length === 0) {
      return "Bitte mindestens eine Position hinzufügen.";
    }
    const incompleteLineIndex = offerDraft.lines.findIndex((line) => !line.title.trim() && !line.catalogItemId);
    if (incompleteLineIndex >= 0) {
      return `Bitte Position ${incompleteLineIndex + 1} auswählen oder eine Bezeichnung eintragen.`;
    }
    const invalidQuantityIndex = offerDraft.lines.findIndex((line) => Number(line.quantity || 0) <= 0);
    if (invalidQuantityIndex >= 0) {
      return `Bitte bei Position ${invalidQuantityIndex + 1} eine Menge größer 0 eintragen.`;
    }
    const invalidPriceIndex = offerDraft.lines.findIndex((line) => Number(line.unitPrice || 0) < 0);
    if (invalidPriceIndex >= 0) {
      return `Bitte bei Position ${invalidPriceIndex + 1} keinen negativen Einzelpreis eintragen.`;
    }
    return "";
  }

  async function deleteOffer(offer: OfferItem) {
    if (!selectedProjectFile) return;
    const confirmed = window.confirm(`Angebot ${offer.offerNumber} wirklich löschen?`);
    if (!confirmed) return;

    const res = await fetch("/api/offers", {
      method: "DELETE",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        id: offer.id,
        actorName: activeUser?.name || "Christian Eid",
      }),
    });

    if (!res.ok) {
      const data = await res.json().catch(() => null);
      setErrorMessage(data?.error ?? "Angebot konnte nicht gelöscht werden.");
      return;
    }

    setOffers((currentOffers) => currentOffers.filter((currentOffer) => currentOffer.id !== offer.id));
    await loadOfferHistory(selectedProjectFile.id);
    await addProjectLogbookEntry(
      selectedProjectFile.id,
      "Angebot",
      `Angebot gelöscht: ${offer.offerNumber}.`
    );
  }

