  function closeManualProjectTimeModal() {
    setIsManualProjectTimeModalOpen(false);
    setStampEditError("");
  }

  async function saveManualProjectTimeEntry() {
    if (!selectedProjectFile) return;
    const startMinutes = parseStampTimeToMinutes(stampEditStartTime);
    const endMinutes = parseStampTimeToMinutes(stampEditEndTime);
    const pauseMs = parseStampPauseToMilliseconds(stampEditPause);
    const selectedUser = users.find((user) => user.id === manualProjectTimeUserId);

    if (!selectedUser) {
      setStampEditError("Bitte einen Mitarbeiter auswählen.");
      return;
    }

    if (!stampEditDate.trim()) {
      setStampEditError("Bitte ein Datum eintragen.");
      return;
    }

    if (startMinutes === null || endMinutes === null || pauseMs === null) {
      setStampEditError("Bitte Zeiten im Format HH:MM und Pause als H:MM:SS eintragen.");
      return;
    }

    const rawDurationMs = (endMinutes - startMinutes) * 60_000 - pauseMs;
    if (rawDurationMs <= 0) {
      setStampEditError("Die Laufzeit muss größer als 0 sein.");
      return;
    }

    const manualEntry: StampTimeEntry = {
      id: crypto.randomUUID(),
      mode: "project",
      projectId: selectedProjectFile.id,
      projectLabel: selectedProjectFile.title,
      userId: selectedUser.id,
      employee: selectedUser.name,
      entrySource: "manual",
      date: normalizeDateKeyValue(stampEditDate.trim()),
      startTime: stampEditStartTime,
      endTime: stampEditEndTime,
      durationMs: rawDurationMs,
      pauseMs,
      comment: stampEditComment.trim() || "Manuell hinzugefügt",
    };

    try {
      await saveStampTimeEntry(manualEntry);
      await addProjectLogbookEntry(
        selectedProjectFile.id,
        "Zeit & Lohn",
        `Manueller Zeiteintrag: ${selectedUser.name}, ${stampEditDate.trim()} ${stampEditStartTime}-${stampEditEndTime}, ${formatStampDuration(rawDurationMs)}.`
      );
      closeManualProjectTimeModal();
    } catch (error) {
      setStampEditError(
        error instanceof Error ? error.message : "Zeiteintrag konnte nicht gespeichert werden."
      );
    }
  }

  function closeStampEntryEditModal() {
    setEditingStampEntry(null);
    setStampEditError("");
  }

  async function saveEditedStampEntry() {
    if (!editingStampEntry) return;

    const startMinutes = parseStampTimeToMinutes(stampEditStartTime);
    const endMinutes = parseStampTimeToMinutes(stampEditEndTime);
    const pauseMs = parseStampPauseToMilliseconds(stampEditPause);

    if (!stampEditDate.trim()) {
      setStampEditError("Bitte ein Datum eintragen.");
      return;
    }

    if (startMinutes === null || endMinutes === null || pauseMs === null) {
      setStampEditError("Bitte Zeiten im Format HH:MM und Pause als H:MM:SS eintragen.");
      return;
    }

    const rawDurationMs = (endMinutes - startMinutes) * 60_000 - pauseMs;
    if (rawDurationMs <= 0) {
      setStampEditError("Die Laufzeit muss gröxer als 0 sein.");
      return;
    }

    const previousSummary = `${editingStampEntry.date} ${editingStampEntry.startTime}-${editingStampEntry.endTime}, Pause ${formatStampDuration(editingStampEntry.pauseMs)}, ${formatStampDuration(editingStampEntry.durationMs)}`;
    const nextSummary = `${normalizeDateKeyValue(stampEditDate.trim())} ${stampEditStartTime}-${stampEditEndTime}, Pause ${formatStampDuration(pauseMs)}, ${formatStampDuration(rawDurationMs)}`;
    const updatedEntry: StampTimeEntry = {
      ...editingStampEntry,
      date: normalizeDateKeyValue(stampEditDate.trim()),
      startTime: stampEditStartTime,
      endTime: stampEditEndTime,
      pauseMs,
      durationMs: rawDurationMs,
      comment: stampEditComment.trim(),
      editHistory: [
        {
          id: crypto.randomUUID(),
          actorUserId: activeUserId,
          actorName: activeUser?.name ?? "",
          event: "Zeiteintrag bearbeitet",
          note: stampEditComment.trim(),
          previousValue: previousSummary,
          nextValue: nextSummary,
          createdAt: new Date().toISOString(),
        },
        ...(editingStampEntry.editHistory ?? []),
      ],
    };

    try {
      await saveStampTimeEntry(updatedEntry);
      closeStampEntryEditModal();
    } catch (error) {
      setStampEditError(
        error instanceof Error ? error.message : "Zeiteintrag konnte nicht gespeichert werden."
      );
    }
  }

  async function deleteEditedStampEntry() {
    if (!editingStampEntry) return;
    const shouldDelete = window.confirm("Diesen Zeiteintrag wirklich löschen?");
    if (!shouldDelete) return;

    const params = new URLSearchParams({
      id: editingStampEntry.id,
      actorUserId: activeUserId,
      actorName: activeUser?.name ?? "",
      note: stampEditComment.trim() || "Zeiteintrag gelöscht",
    });
    const res = await fetch(`/api/project-time-entries?${params.toString()}`, {
      method: "DELETE",
    });

    if (!res.ok) {
      const data = await res.json().catch(() => null);
      setStampEditError(data?.error ?? "Zeiteintrag konnte nicht gelöscht werden.");
      return;
    }

    const deletedEntry = (await res.json()) as StampTimeEntry;
    setStampEntries((currentEntries) =>
      currentEntries.map((entry) => (entry.id === deletedEntry.id ? deletedEntry : entry))
    );
    closeStampEntryEditModal();
  }

  async function closeCurrentStampSession(comment: string) {
    if (!stampSession) return null;

    const res = await fetch("/api/stamp-session", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        action: "stop",
        userId: activeUser?.id || activeUserId,
        comment,
      }),
    });

    if (!res.ok) {
      const data = await res.json().catch(() => null);
      setStampError(data?.error ?? "Stempelung konnte nicht gespeichert werden.");
      throw new Error(data?.error ?? "Stempelung konnte nicht gespeichert werden.");
    }

    const savedEntry = (await res.json()) as StampTimeEntry;
    const normalizedSavedEntry = { ...savedEntry, date: normalizeDateKeyValue(savedEntry.date) };
    setStampEntries((currentEntries) => [
      normalizedSavedEntry,
      ...currentEntries.filter((currentEntry) => currentEntry.id !== normalizedSavedEntry.id),
    ]);
    setStampSession(null);
    return normalizedSavedEntry;
  }

  async function saveFinalInspectionForStamp(entry: StampTimeEntry) {
    if (entry.mode !== "project" || !entry.projectId) return;

    const res = await fetch("/api/final-inspections", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        projectId: entry.projectId,
        projectLabel: entry.projectLabel || getStampProjectLabel(entry.projectId),
        employee: entry.employee || activeUser?.name || "",
        comment: stampComment.trim(),
        status: finalInspectionByColleague ? "colleague" : "completed",
        checklist: finalInspectionItems.map((label, index) => ({
          label,
          done: finalInspectionChecks[index] ?? false,
        })),
        upsellNotes: finalInspectionHasUpsell ? finalInspectionUpsellNotes.trim() : "",
      }),
    });

    if (!res.ok) {
      const data = await res.json().catch(() => null);
      throw new Error(data?.error ?? "Endkontrolle konnte nicht gespeichert werden.");
    }

    await loadProjectLogbookEntries();
    if (finalInspectionHasUpsell) {
      const project = heroProjects.find((item) => item.id === entry.projectId);
      if (project) {
        await createProjectPotential(project, finalInspectionUpsellNotes.trim());
      }
      await loadNotifications(true);
    }
  }

  async function toggleStampTimer() {
    if (!stampSession) {
      openStampStartModal();
      return;
    }

    const action = stampSession.pauseStartedAt ? "resume" : "pause";
    const res = await fetch("/api/stamp-session", {
      method: "PATCH",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        action,
        userId: activeUser?.id || activeUserId,
      }),
    });

    if (!res.ok) {
      const data = await res.json().catch(() => null);
      setErrorMessage(data?.error ?? "Stempelung konnte nicht aktualisiert werden.");
      await loadActiveStampSession({ silent: true });
      return;
    }

    const data = (await res.json()) as ActiveStampSessionResponse;
    setStampSession(mapActiveStampSession(data));
    setTimerNow(Date.now());
  }

  async function confirmStampModal() {
    const requiresProjectCompletionState =
      (stampModalMode === "change" || stampModalMode === "stop") &&
      stampSession?.mode === "project";
    const onlyProjectFollowUp =
      stampModalMode === "change" && stampSession?.mode === "unproductive";
    const selectedNextProject =
      stampSelectionMode === "project"
        ? heroProjects.find((project) => project.id === stampProjectId)
        : null;
    const nextProjectId = selectedNextProject?.id ?? "";
    if (stampModalMode !== "stop" && stampSelectionMode === "project" && !selectedNextProject) {
      setStampError("Bitte ein Projekt auswählen.");
      return;
    }
    if ((stampModalMode === "change" || stampModalMode === "stop") && !stampComment.trim()) {
      setStampError("Bitte einen Kommentar zur abgeschlossenen Stempelung eingeben.");
      return;
    }
    if (requiresProjectCompletionState) {
      if (!stampCompletionState) {
        setStampError("Bitte auswählen, ob die Arbeit fertig oder unterbrochen ist.");
        return;
      }
      if (
        stampCompletionState === "finished" &&
        !finalInspectionByColleague &&
        finalInspectionHasUpsell &&
        !finalInspectionUpsellNotes.trim()
      ) {
        setStampError("Bitte kurz notieren, welche Zusatzverkaufsmöglichkeit erkannt wurde.");
        return;
      }
    }

    if (stampModalMode === "change" || stampModalMode === "stop") {
      try {
        const closedEntry = await closeCurrentStampSession(stampComment.trim());
        if (requiresProjectCompletionState && closedEntry && stampCompletionState === "finished") {
          await saveFinalInspectionForStamp(closedEntry);
        }
      } catch (error) {
        setStampError(
          error instanceof Error ? error.message : "Stempelung konnte nicht gespeichert werden."
        );
        return;
      }
    }

    if (stampModalMode === "stop") {
      setStampSession(null);
      setIsStampModalOpen(false);
      setStampComment("");
      setStampError("");
      resetStampCompletionState();
      return;
    }

    try {
      await startStampSession(stampSelectionMode, nextProjectId);
      setIsStampModalOpen(false);
      setStampComment("");
      setStampError("");
      resetStampCompletionState();
    } catch (error) {
      setStampError(
        error instanceof Error ? error.message : "Stempelung konnte nicht gestartet werden."
      );
    }
  }

  function startEditTimeEntry(entry: TimeEntryItem) {
    setEditingTimeEntryId(entry.id);
    setZeitDauer(String(entry.dauerMinuten));
    setZeitNotiz(entry.notiz);
  }

  function cancelEditTimeEntry() {
    setEditingTimeEntryId(null);
    setZeitDauer("");
    setZeitNotiz("");
  }

  async function deleteTimeEntry(entry: TimeEntryItem) {
    if (!editingTask) return;

    const reason = window.prompt("Bitte Begr\u00fcndung f\u00fcr das L\u00f6schen des Zeiteintrags angeben:");
    if (!reason?.trim()) {
      setErrorMessage("Zeiteinträge können nur mit Begründung gelöscht werden.");
      return;
    }

    const res = await fetch(`/api/tasks/${editingTask.id}/time-entries`, {
      method: "DELETE",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        entryId: entry.id,
        actorId: activeUserId,
        reason,
      }),
    });

    if (!res.ok) {
      const data = await res.json().catch(() => null);
      setErrorMessage(data?.error ?? "Zeiteintrag konnte nicht gelöscht werden.");
      return;
    }

    setEditingTask((current) => {
      if (!current) return current;

      return {
        ...current,
        gesamtzeitMinuten: current.gesamtzeitMinuten - entry.dauerMinuten,
        zeiteintraege: current.zeiteintraege.filter((timeEntry) => timeEntry.id !== entry.id),
      };
    });
    if (editingTimeEntryId === entry.id) cancelEditTimeEntry();
    await loadTasks();
    await loadNotifications(true);
  }

  async function addComment() {
    if (!editingTask || !kommentarText.trim()) return;
    if (getTaskAcceptanceStatusForActiveUser(editingTask) !== "accepted") {
      showTaskAcceptanceRequiredMessage();
      return;
    }

    const res = await fetch(`/api/tasks/${editingTask.id}/comments`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        actorId: activeUserId,
        text: kommentarText,
        recipientUserId: commentRecipientUserId || null,
      }),
    });

    if (!res.ok) {
      const data = await res.json().catch(() => null);
      setErrorMessage(data?.error ?? "Kommentar konnte nicht gespeichert werden.");
      return;
    }

    const comment = await res.json();
    setEditingTask((current) => {
      if (!current) return current;

      return {
        ...current,
        kommentare: [comment, ...(current.kommentare ?? [])],
        history: [
          ...(current.history ?? []),
          {
            id: `local-comment-${Date.now()}`,
            event: "Kommentar hinzugefügt",
            actorName: activeUser?.name ?? "Aktueller Benutzer",
            note: commentRecipientUserId
              ? `An ${
                  editingTask.participants.find(
                    (participant) => participant.userId === commentRecipientUserId
                  )?.userName ?? "Beteiligten"
                }: ${kommentarText.trim()}`
              : kommentarText.trim(),
            createdAt: new Date().toISOString(),
          },
        ],
      };
    });
    setKommentarText("");
    setCommentRecipientUserId("");
    await loadTasks();
    await loadNotifications(true);
  }

  async function deleteTask(
    event: MouseEvent<HTMLButtonElement>,
    taskId: string,
    permanent = false
  ) {
    event.stopPropagation();

    const confirmed = window.confirm(
      permanent
        ? "Aufgabe endgültig aus dem Archiv löschen?"
        : "Aufgabe ins Archiv verschieben?"
    );
    if (!confirmed) return;

    const res = await fetch("/api/tasks", {
      method: "DELETE",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ id: taskId, actorId: activeUserId, permanent }),
    });

    if (!res.ok) {
      const data = await res.json().catch(() => null);
      setErrorMessage(data?.error ?? "Aufgabe konnte nicht gel\u00f6scht werden.");
      return;
    }

    await loadTasks();
    await loadAbsences();
    await loadNotifications(true);
  }

  async function moveTaskToStatus(task: TaskItem, nextStatus: TaskStatus) {
    if (task.status === nextStatus) return;

    setTasks((currentTasks) =>
      currentTasks.map((currentTask) =>
        currentTask.id === task.id ? { ...currentTask, status: nextStatus } : currentTask
      )
    );

    const res = await fetch("/api/tasks", {
      method: "PATCH",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        id: task.id,
        actorId: activeUserId,
        title: task.titel,
        description: task.beschreibung,
        status: nextStatus,
        priority: task.prioritaet,
        ownerId: task.zustaendigId,
        deadline: task.faelligkeit,
        customer: task.kunde,
        customerClass: task.kundenklasse || null,
        autoFeedbackEnabled: task.autoFeedbackEnabled,
        autoFeedbackRecipientId: task.autoFeedbackEnabled ? task.autoFeedbackRecipientId : null,
        recurrenceEnabled: task.recurrenceEnabled,
        recurrenceInterval: task.recurrenceEnabled ? task.recurrenceInterval : null,
        estimateMinutes: task.vorgabeMinuten,
      }),
    });

    if (!res.ok) {
      const data = await res.json().catch(() => null);
      setErrorMessage(data?.error ?? "Status konnte nicht aktualisiert werden.");
      await loadTasks();
      return;
    }

    await loadTasks();
  }

  async function respondToTask(
    event: MouseEvent<HTMLButtonElement>,
    task: TaskItem,
    response: "accepted" | "rejected"
  ) {
    event.stopPropagation();
    await respondToTaskAction(task, response);
  }

  async function respondToTaskAction(task: TaskItem, response: "accepted" | "rejected") {
    const reason =
      response === "rejected"
        ? window.prompt("Bitte Begründung für die Ablehnung angeben:")
        : "";

    if (response === "rejected" && !reason?.trim()) {
      setErrorMessage("Eine Aufgabe kann nur mit Begründung abgelehnt werden.");
      return;
    }

    const res = await fetch("/api/tasks/respond", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        taskId: task.id,
        actorId: activeUserId,
        response,
        reason,
      }),
    });

    if (!res.ok) {
      const data = await res.json().catch(() => null);
      setErrorMessage(data?.error ?? "Antwort konnte nicht gespeichert werden.");
      return;
    }

    await loadTasks();
    await loadNotifications(true);
  }

  async function addTaskParticipant() {
    if (!editingTask || !taskParticipantUserId) return;
    if (isTaskEditingLocked()) {
      showTaskAcceptanceRequiredMessage();
      return;
    }

    const res = await fetch("/api/tasks", {
      method: "PATCH",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        id: editingTask.id,
        actorId: activeUserId,
        addParticipantUserId: taskParticipantUserId,
      }),
    });

    if (!res.ok) {
      const data = await res.json().catch(() => null);
      setErrorMessage(data?.error ?? "Beteiligter konnte nicht hinzugefügt werden.");
      return;
    }

    const updatedTask = (await res.json()) as TaskItem;
    setEditingTask(updatedTask);
    setTasks((currentTasks) =>
      currentTasks.map((task) => (task.id === updatedTask.id ? updatedTask : task))
    );
    setTaskParticipantUserId("");
    await loadNotifications(true);
  }

  async function restoreTask(event: MouseEvent<HTMLButtonElement>, taskId: string) {
    event.stopPropagation();

    const res = await fetch("/api/tasks", {
      method: "PATCH",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ id: taskId, actorId: activeUserId, restore: true }),
    });

    if (!res.ok) {
      const data = await res.json().catch(() => null);
      setErrorMessage(data?.error ?? "Aufgabe konnte nicht wiederhergestellt werden.");
      return;
    }

    await loadTasks();
  }

  function handleKanbanDrop(nextStatus: TaskStatus) {
    if (!draggedTaskId) return;

    const task = tasks.find((currentTask) => currentTask.id === draggedTaskId);
    setDraggedTaskId(null);

    if (!task) return;
    moveTaskToStatus(task, nextStatus);
  }

